            newWalletId = `wal_${Math.random().toString(36).substring(2, 10).toUpperCase()}`
        } else {
            console.warn(`[MASTER] Asaas Key inativa. Usando Mock Wallet: ${newWalletId}`)
        }

        // 4. Efetivar as Aprovações no Banco (Transaction Simulada)
        // A. Ativa a Escola e Seta a Wallet
        const { error: updateTenantErr } = await supabase
            .from('tenants')
            .update({ status: 'active', asaas_wallet_id: newWalletId })
            .eq('id', tenantId)

        if (updateTenantErr) throw updateTenantErr

        // B. Promove a Sessão do Dono para "Professor/Escola"
        const { error: updateUserErr } = await supabase
            .from('users')
            .update({ role: 'escola' })
            .eq('id', tenant.owner_id)

        if (updateUserErr) throw updateUserErr

        return NextResponse.json({
            success: true,
            message: 'Partner Approved and Wallet assigned.',
            walletId: newWalletId
        })

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
    } catch (e: any) {
        console.error("Master Approve Error:", e)
        return NextResponse.json({ error: e.message || 'Server Exception' }, { status: 500 })
    }
}

import { createServerClient } from '@supabase/ssr'
import { cookies } from 'next/headers'
import { NextResponse } from 'next/server'
import { rateLimit, getClientIp } from '@/utils/rate-limit'

export async function POST(request: Request) {
    // Rate limit: max 3 partner applications per minute per IP
    const ip = getClientIp(request);
    const { limited } = rateLimit(`partner:${ip}`, 3);
    if (limited) {
        return NextResponse.json(
            { error: 'Muitas tentativas. Tente novamente em 1 minuto.' },
            { status: 429, headers: { 'Retry-After': '60' } }
        );
    }

    try {
        const cookieStore = await cookies()
        const supabase = createServerClient(
            process.env.NEXT_PUBLIC_SUPABASE_URL!,
            process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
            { cookies: { get: (name) => cookieStore.get(name)?.value } }
        )

        // 1. Validar a Sessão
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

        // 2. Coletar os dados do Formulário
        const body = await request.json()
        const { schoolName, instagram, videoUrl } = body

        if (!schoolName || !instagram) {
            return NextResponse.json({ error: 'Nome da Escola e Instagram são obrigatórios.' }, { status: 400 })
        }

        // 3. Checar se ele já tem uma aplicação
        const { data: existingApp } = await supabase
            .from('tenants')
            .select('id')
            .eq('owner_id', user.id)
            .single()

        if (existingApp) {
            return NextResponse.json({ error: 'Você já possui uma aplicação enviada ou uma Escola Ativa.' }, { status: 400 })
        }

        // 4. Inserir Inquilino no Banco (Ainda Pendente)
        const { error: insertError } = await supabase.from('tenants').insert({
            owner_id: user.id,
            name: schoolName,
            instagram: instagram,
            video_url: videoUrl,
            status: 'pending' // Ainda precisa ser aprovado via /master
        })

        if (insertError) {
            console.error("Partner Application DB Error:", insertError)
            return NextResponse.json({ error: 'Falha gravando solicitação no Banco de Dados.' }, { status: 500 })
        }

        return NextResponse.json({ success: true, message: 'Application submitted successfully.' })
    } catch (e: any) {
        console.error("Error creating partner application:", e)
        return NextResponse.json({ error: e.message || 'Server Exception' }, { status: 500 })
    }
}

import { createServerClient } from '@supabase/ssr';
import { cookies } from 'next/headers';
import { NextResponse } from 'next/server';

export async function POST(req: Request) {
    try {
        const { lessonId, progressPercent } = await req.json();

        if (!lessonId) {
            return NextResponse.json({ error: 'Lesson ID is required' }, { status: 400 });
        }

        // Se progress não for passado, considerar como um Ping. Para Reward de 90% exige a prop.
        if (progressPercent < 90) {
            return NextResponse.json({ status: 'ignored_ping', message: 'Progresso insuficiente para XP' }, { status: 200 });
        }

        const cookieStore = await cookies();
        const supabase = createServerClient(
            process.env.NEXT_PUBLIC_SUPABASE_URL!,
            process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
            { cookies: { getAll: () => cookieStore.getAll() } }
        );
        const { data: { user } } = await supabase.auth.getUser();

        if (!user) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        // Verificar se esse usuário já ganhou essa XP específica no banco para não registrar duplo payload
        const { data: existingProgress } = await supabase
            .from('progress')
            .select('id, completed, xp_awarded')
            .eq('user_id', user.id)
            .eq('lesson_id', lessonId)
            .single();

        if (existingProgress?.completed) {
            return NextResponse.json({ status: 'already_completed', xp_awarded: existingProgress.xp_awarded }, { status: 200 });
        }

        // Marcar como concluído +50 XP (Hardcode, mas poderia vir da aula)
        const xpAmount = 50;

        const { data: newProgress, error } = await supabase
            .from('progress')
            .upsert({
                user_id: user.id,
                lesson_id: lessonId,
                completed: true,
                completed_at: new Date().toISOString(),
                xp_awarded: xpAmount
            }, { onConflict: 'user_id, lesson_id' })
            .select()
            .single();

        if (error) {
            throw error;
        }

        return NextResponse.json({ status: 'success', xp_earned: xpAmount, lessonId: newProgress.lesson_id }, { status: 200 });

    } catch (error: any) {
        console.error('API /progress/track Error:', error);
        return NextResponse.json({ error: error?.message || 'Internal Server Error' }, { status: 500 });
    }
}

