'use client';

import { Users, Search, Filter, ShieldCheck, UserX, RefreshCw } from 'lucide-react';
import { useEffect, useState } from 'react';
import { createClient } from '@/utils/supabase/client';

interface Student {
    id: string;
    email: string;
    full_name: string;
    role: string;
    created_at: string;
}

export default function MasterStudentsPage() {
    const [students, setStudents] = useState<Student[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const supabase = createClient();

    const fetchStudents = async () => {
        setLoading(true);
        const { data, error } = await supabase
            .from('users')
            .select('id, email, full_name, role, created_at')
            .order('created_at', { ascending: false });
        if (!error && data) setStudents(data);
        setLoading(false);
    };

    useEffect(() => { fetchStudents(); }, []);

    const handleBan = async (userId: string) => {
        if (!confirm("Tem certeza que deseja banir este aluno? Ele perderá acesso a todas as aulas.")) return;
        // Banir = mudar role para 'banned' (ou deletar, conforme regra de negócio)
        const { error } = await supabase.from('users').update({ role: 'banned' }).eq('id', userId);
        if (error) { alert("Erro: " + error.message); return; }
        alert("Aluno banido da plataforma.");
        fetchStudents();
    };

    const filtered = students.filter(s =>
        s.full_name?.toLowerCase().includes(search.toLowerCase()) ||
        s.email?.toLowerCase().includes(search.toLowerCase())
    );

    return (
        <div className="space-y-8 animate-fade-in pb-20">
            <div>
                <h1 className="text-3xl font-display font-bold text-white uppercase tracking-wider mb-2">
                    ALUNOS GLOBAIS
                </h1>
                <p className="text-[#888] font-mono text-sm uppercase tracking-widest">
                    Visão Geral de todos os consumidores da Plataforma
                </p>
            </div>

            <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded p-4 flex flex-col md:flex-row gap-4 justify-between items-center">
                <div className="relative w-full md:w-96">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-[#666]" size={18} />
                    <input
                        type="text"
                        value={search}
                        onChange={e => setSearch(e.target.value)}
                        placeholder="Buscar aluno por nome ou email..."
                        className="w-full bg-[#111] border border-[#222] rounded-full py-2 pl-10 pr-4 text-sm text-white placeholder:text-[#555] focus:outline-none focus:border-red-500/50 transition-colors"
                    />
                </div>
                <div className="flex gap-2 w-full md:w-auto">
                    <button onClick={fetchStudents} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 border border-[#222] bg-[#111] text-[#888] rounded-full text-sm font-medium hover:text-white hover:border-[#333] transition-colors">
                        <RefreshCw size={16} className={loading ? 'animate-spin' : ''} /> Sincronizar
                    </button>
                </div>
            </div>

            <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-[#111] text-[#666] text-xs uppercase font-mono tracking-widest border-b border-[#222]">
                                <th className="p-4 font-normal">Aluno</th>
                                <th className="p-4 font-normal">Role</th>
                                <th className="p-4 font-normal hidden md:table-cell">Membro Desde</th>
                                <th className="p-4 font-normal text-right">Ações Globais</th>
                            </tr>
                        </thead>
                        <tbody className="text-sm font-sans divide-y divide-[#1a1a1a]">
                            {loading ? (
                                <tr><td colSpan={4} className="p-8 text-center text-[#555]">Carregando cadastros...</td></tr>
                            ) : filtered.length === 0 ? (
                                <tr><td colSpan={4} className="p-8 text-center text-[#555]">Nenhum aluno encontrado.</td></tr>
                            ) : (
                                filtered.map((aluno) => (
                                    <tr key={aluno.id} className="hover:bg-[#111] transition-colors group">
                                        <td className="p-4">
                                            <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center font-bold text-[#888] font-mono text-xs">
                                                    {(aluno.full_name || aluno.email || '?').charAt(0).toUpperCase()}
                                                </div>
                                                <div>
                                                    <p className="text-white font-medium">{aluno.full_name || 'Sem nome'}</p>
                                                    <p className="text-[#666] text-xs font-mono">{aluno.email}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="p-4">
                                            <span className={`text-xs font-mono uppercase px-2 py-0.5 rounded border
                                                ${aluno.role === 'admin' ? 'text-red-500 border-red-500/30 bg-red-500/10' :
                                                    aluno.role === 'escola' ? 'text-purple-400 border-purple-400/30 bg-purple-400/10' :
                                                        'text-[#888] border-[#333] bg-[#111]'}
                                            `}>
                                                {aluno.role}
                                            </span>
                                        </td>
                                        <td className="p-4 text-[#666] hidden md:table-cell font-mono text-xs">
                                            {new Date(aluno.created_at).toLocaleDateString('pt-BR')}
                                        </td>
                                        <td className="p-4 text-right">
                                            <div className="flex items-center justify-end gap-2">
                                                <button className="p-2 text-[#666] hover:text-white hover:bg-[#222] rounded transition-colors" title="Ver Perfil Global">
                                                    <Users size={16} />
                                                </button>
                                                {aluno.role !== 'admin' && (
                                                    <button onClick={() => handleBan(aluno.id)} className="p-2 text-[#666] hover:text-red-500 hover:bg-red-500/10 rounded transition-colors" title="Banir Aluno (Quebra Termos)">
                                                        <UserX size={16} />
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

'use client';

import { Search, Plus, Filter, MoreVertical, ShieldCheck, Ban, Edit2, PlayCircle, CheckCircle, RefreshCw } from "lucide-react";
import { useEffect, useState } from "react";
import { createClient } from "@/utils/supabase/client";

interface School {
    id: string;
    name: string;
    status: 'pending' | 'active' | 'suspended';
    created_at: string;
    createdAt?: string; // Added createdAt property
    owner: { full_name: string; email: string };
    _courses_count: number;
}

export default function MasterSchoolsPage() {
    const [schools, setSchools] = useState<School[]>([]);
    const [loading, setLoading] = useState(true);
    const supabase = createClient();

    const fetchSchools = async () => {
        setLoading(true);
        // Supabase query to get tenants + nested owner + count courses
        const { data, error } = await supabase
            .from('tenants')
            .select(`
                id, name, status, created_at,
                owner:users!owner_id(full_name, email)
            `)
            .order('created_at', { ascending: false });

        if (!error && data) {
            setSchools(data as unknown as School[]); // Corrected typing
        }
        setLoading(false);
    }

    useEffect(() => { fetchSchools() }, []); // desativando regra pois a func é useCallback ou interna

    const approveSchool = async (tenantId: string) => { // Renamed handleApprove to approveSchool
        if (!confirm("Deseja aprovar esta escola, criar C/C na Asaas e dar permissão de Studio ao Dono?")) return;

        try {
            const res = await fetch('/api/master/schools/approve', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ tenantId })
            });
            const result = await res.json();
            if (!res.ok) throw new Error(result.error);
            alert("✅ Escola Aprovada Oficialmente! Carteira gerada: " + result.walletId);
            fetchSchools();
        } catch (e: any) {
            alert("Erro: " + e.message);
        }
    }

    return (
        <div className="max-w-7xl mx-auto pb-10">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-8 gap-4">
                <div>
                    <h1 className="text-3xl font-heading font-bold text-white uppercase tracking-tight mb-2">Escolas & Criadores</h1>
                    <p className="text-[#888] font-sans text-sm">Gerencie os Inquilinos Multi-Tenant, aprovações, bloqueios master e Split Asaas.</p>
                </div>
                <div className="flex gap-3">
                    <button onClick={fetchSchools} className="flex items-center gap-2 bg-[#111] hover:bg-[#1a1a1a] border border-[#222] text-[#aaa] px-4 py-2.5 rounded font-mono text-sm uppercase transition-all">
                        <RefreshCw size={18} className={loading ? "animate-spin" : ""} /> Sync
                    </button>
                    <button className="flex items-center gap-2 bg-[#111] hover:bg-[#1a1a1a] border border-[#222] text-white px-5 py-2.5 rounded font-mono text-sm uppercase tracking-wider font-bold transition-all">
                        <Filter size={18} /> Filtrar
                    </button>
                    <button className="flex items-center gap-2 bg-red-600 hover:bg-red-700 text-white px-5 py-2.5 rounded font-mono text-sm uppercase tracking-wider font-bold transition-all shadow-[0_0_15px_rgba(220,38,38,0.5)]">
                        <Plus size={18} /> Cadastrar Escola
                    </button>
                </div>
            </div>

            {/* Listagem Table UI */}
            <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded-sm overflow-hidden">
                <div className="p-4 border-b border-[#1a1a1a] flex gap-4">
                    <div className="flex-1 relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-[#555]" size={18} />
                        <input
                            type="text"
                            placeholder="Buscar inquilino por nome ou ID..."
                            className="w-full bg-[#111] border border-[#222] rounded py-2 pl-10 pr-4 text-white text-sm focus:outline-none focus:border-red-500/50 transition-colors"
                        />
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-[#111] border-b border-[#222] text-xs font-mono uppercase tracking-widest text-[#888]">
                                <th className="p-4 font-normal">Inquilino (Escola)</th>
                                <th className="p-4 font-normal">Master Owner</th>
                                <th className="p-4 font-normal">Cursos</th>
                                <th className="p-4 font-normal">Mês</th> {/* Added new column */}
                                <th className="p-4 font-normal">Status Asaas</th>
                                <th className="p-4 font-normal text-right">Controles</th>
                            </tr>
                        </thead>
                        <tbody className="text-sm font-sans divide-y divide-[#1a1a1a]">
                            {loading ? (
                                <tr><td colSpan={6} className="p-8 text-center text-[#555]">Carregando rede...</td></tr>
                            ) : schools.length === 0 ? (
                                <tr><td colSpan={6} className="p-8 text-center text-[#555]">Nenhum inquilino cadastrado na sua operação local.</td></tr>
                            ) : (
                                schools.map(s => (
                                    <SchoolRow
                                        key={s.id}
                                        id={s.id}
                                        name={s.name}
                                        owner={s.owner?.full_name || s.owner?.email || "N/A"}
                                        status={s.status}
                                        createdAt={s.created_at} // Pass created_at to SchoolRow
                                        onApprove={() => approveSchool(s.id)} // Changed to approveSchool
                                    />
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

function SchoolRow({ name, id, owner, status, onApprove }: any) {
    return (
        <tr className="hover:bg-[#111] transition-colors group">
            <td className="p-4">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded bg-[#1a1a1a] border border-[#222] flex items-center justify-center shrink-0">
                        <span className="text-[#666] font-heading font-bold">{name.substring(0, 2).toUpperCase()}</span>
                    </div>
                    <div>
                        <p className="font-bold text-white">{name}</p>
                        <p className="text-[10px] text-[#666] font-mono">{id}</p>
                    </div>
                </div>
            </td>
            <td className="p-4 text-[#aaa]">{owner}</td>
            <td className="p-4 text-[#aaa] flex items-center gap-2 mt-2"><PlayCircle size={14} /> 0</td>
            <td className="p-4 font-display font-medium text-white">R$ 0</td>
            <td className="p-4">
                {status === 'active' && <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded bg-green-500/10 text-green-500 text-xs font-mono uppercase tracking-widest border border-green-500/20"><ShieldCheck size={14} /> Ativo (Split OK)</span>}
                {status === 'pending' && <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded bg-yellow-500/10 text-yellow-500 text-xs font-mono uppercase tracking-widest border border-yellow-500/20">Aguardando Avaliação</span>}
                {status === 'suspended' && <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded bg-red-500/10 text-red-500 text-xs font-mono uppercase tracking-widest border border-red-500/20"><Ban size={14} /> Suspenso</span>}
            </td>
            <td className="p-4 text-right">
                <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    {status === 'pending' && (
                        <button onClick={onApprove} className="p-2 text-green-500/70 hover:text-green-500 hover:bg-green-500/10 rounded transition-colors" title="Aprovar e Criar Split Asaas">
                            <CheckCircle size={16} />
                        </button>
                    )}
                    <button className="p-2 text-[#888] hover:text-white hover:bg-[#222] rounded transition-colors" title="Editar Contrato">
                        <Edit2 size={16} />
                    </button>
                    <button className="p-2 text-red-500/70 hover:text-red-500 hover:bg-red-500/10 rounded transition-colors" title="Suspender Operação">
                        <Ban size={16} />
                    </button>
                </div>
            </td>
        </tr>
    );
}

'use client';

import {
    Users,
    TrendingUp,
    DollarSign,
    ArrowUpRight,
    ShieldCheck,
    AlertOctagon,
    Building2,
    Activity,
    CheckCircle,
    XCircle,
    RefreshCw
} from "lucide-react";
import { useEffect, useState } from "react";
import { createClient } from "@/utils/supabase/client";
import Link from "next/link";

interface DashboardData {
    totalTenants: number;
    activeTenants: number;
    pendingTenants: number;
    totalUsers: number;
    totalTransactions: number;
    totalRevenue: number;
    pendingSchools: { id: string; name: string; owner_name: string; instagram: string }[];
}

export default function MasterDashboardPage() {
    const [data, setData] = useState<DashboardData | null>(null);
    const [loading, setLoading] = useState(true);
    const supabase = createClient();

    const fetchDashboard = async () => {
        setLoading(true);

        const [tenantsRes, usersRes, txRes, pendingRes] = await Promise.all([
            supabase.from('tenants').select('id, status'),
            supabase.from('users').select('id', { count: 'exact', head: true }),
            supabase.from('transactions').select('amount, status').eq('status', 'confirmed'),
            supabase.from('tenants').select(`id, name, instagram, owner:users!owner_id(full_name)`).eq('status', 'pending').order('created_at', { ascending: false }).limit(5),
        ]);

        const tenants = tenantsRes.data || [];
        const totalRevenue = (txRes.data || []).reduce((acc: number, t: any) => acc + Number(t.amount || 0), 0);

        setData({
            totalTenants: tenants.length,
            activeTenants: tenants.filter(t => t.status === 'active').length,
            pendingTenants: tenants.filter(t => t.status === 'pending').length,
            totalUsers: usersRes.count || 0,
            totalTransactions: (txRes.data || []).length,
            totalRevenue,
            pendingSchools: (pendingRes.data || []).map((s: any) => ({
                id: s.id,
                name: s.name,
                owner_name: s.owner?.full_name || 'N/A',
                instagram: s.instagram || '',
            })),
        });
        setLoading(false);
    };

    useEffect(() => { fetchDashboard(); }, []);

    const handleApprove = async (tenantId: string) => {
        if (!confirm("Aprovar esta escola e criar Sub-Conta Asaas?")) return;
        try {
            const res = await fetch('/api/master/schools/approve', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ tenantId })
            });
            const result = await res.json();
            if (!res.ok) throw new Error(result.error);
            alert("✅ Escola aprovada! Wallet: " + result.walletId);
            fetchDashboard();
        } catch (e: any) {
            alert("Erro: " + e.message);
        }
    };

    const handleReject = async (tenantId: string) => {
        if (!confirm("Recusar e remover esta solicitação?")) return;
        const { error } = await supabase.from('tenants').delete().eq('id', tenantId);
        if (error) { alert("Erro: " + error.message); return; }
        fetchDashboard();
    };

    const xpaceRevenue = data ? data.totalRevenue * 0.15 : 0;

    return (
        <div className="max-w-7xl mx-auto pb-10">
            <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-heading font-bold text-white uppercase tracking-tight mb-2">Suprema Corte XPACE</h1>
                    <p className="text-[#888] font-sans text-sm">Visão global da Plataforma (Todas as Escolas Combinadas). Acesso restrito Nível 5.</p>
                </div>
                <div className="flex items-center gap-3">
                    <button onClick={fetchDashboard} className="flex items-center gap-2 bg-[#111] border border-[#222] px-4 py-2 rounded-sm text-[#aaa] text-xs font-mono uppercase hover:text-white transition-colors">
                        <RefreshCw size={14} className={loading ? 'animate-spin' : ''} /> Sync
                    </button>
                    <div className="flex items-center gap-2 bg-[#111] border border-[#222] px-4 py-2 rounded-sm">
                        <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                        <span className="font-mono text-xs text-[#aaa] uppercase tracking-widest">Sistemas Operacionais</span>
                    </div>
                </div>
            </div>

            {/* KPIs */}
            <h2 className="text-xl font-heading font-bold text-white uppercase tracking-wide mb-4 flex items-center gap-2">
                <DollarSign className="text-primary" /> Faturamento Global (Hoje)
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-10">
                <MetricCard
                    title="Volume Bruto (GMV)"
                    value={loading ? '...' : `R$ ${data?.totalRevenue.toLocaleString('pt-BR', { minimumFractionDigits: 2 }) || '0'}`}
                    trend={`${data?.totalTransactions || 0} transações`}
                    icon={<Activity />}
                    isMoney
                />
                <MetricCard
                    title="Net Revenue XPACE (15%)"
                    value={loading ? '...' : `R$ ${xpaceRevenue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`}
                    trend="Split automático"
                    icon={<DollarSign />}
                    isMoney
                    highlight
                />
                <MetricCard
                    title="Alunos Ativos (Global)"
                    value={loading ? '...' : String(data?.totalUsers || 0)}
                    trend="cadastrados"
                    icon={<Users />}
                />
                <MetricCard
                    title="Escolas Registradas"
                    value={loading ? '...' : String(data?.totalTenants || 0)}
                    trend={`${data?.pendingTenants || 0} na fila`}
                    icon={<Building2 />}
                />
            </div>

            {/* Lower Grids */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* Pending Schools */}
                <div className="lg:col-span-2 bg-[#0a0a0a] border border-[#1a1a1a] rounded-sm p-6 relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 opacity-5"><ShieldCheck size={120} /></div>
                    <div className="flex justify-between items-center mb-6 relative z-10">
                        <h2 className="font-heading font-bold uppercase text-white tracking-wide flex items-center gap-2">
                            <AlertOctagon className="text-accent" size={18} /> Escolas Pendentes de Aprovação
                        </h2>
                        <Link href="/master/escolas" className="text-xs text-primary font-mono hover:text-white transition-colors">VER FILA COMPLETA</Link>
