'use client';

import { useEffect, useState } from 'react';
import { Plus, Search, Video, Edit2, Trash2, Eye, EyeOff, PlayCircle, Loader2 } from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';

interface Course {
    id: string;
    title: string;
    description: string | null;
    price: number;
    thumbnail_url: string | null;
    is_published: boolean;
    pricing_type: string;
    lesson_count: number;
    module_count: number;
    created_at: string;
}

export default function StudioCoursesPage() {
    const [courses, setCourses] = useState<Course[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const router = useRouter();

    const fetchCourses = async () => {
        setLoading(true);
        const res = await fetch('/api/studio/courses');
        const data = await res.json();
        setCourses(data.courses || []);
        setLoading(false);
    };

    useEffect(() => { fetchCourses(); }, []);

    const handleDelete = async (id: string, title: string) => {
        if (!confirm(`Tem certeza que deseja excluir o curso "${title}"? Esta ação é irreversível.`)) return;
        const res = await fetch(`/api/studio/courses/${id}`, { method: 'DELETE' });
        if (res.ok) {
            setCourses(prev => prev.filter(c => c.id !== id));
        } else {
            const err = await res.json();
            alert('Erro ao excluir: ' + err.error);
        }
    };

    const handleTogglePublish = async (course: Course) => {
        const res = await fetch(`/api/studio/courses/${course.id}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ is_published: !course.is_published }),
        });
        if (res.ok) {
            setCourses(prev => prev.map(c => c.id === course.id ? { ...c, is_published: !c.is_published } : c));
        }
    };

    const filtered = courses.filter(c => {
        const matchSearch = c.title.toLowerCase().includes(search.toLowerCase());
        const matchStatus = statusFilter === 'all' ||
            (statusFilter === 'published' && c.is_published) ||
            (statusFilter === 'draft' && !c.is_published);
        return matchSearch && matchStatus;
    });

    return (
        <div className="max-w-6xl mx-auto pb-10">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-8 gap-4">
                <div>
                    <h1 className="text-3xl font-heading font-bold text-white uppercase tracking-tight mb-2">Editor de Cursos</h1>
                    <p className="text-[#888] font-sans text-sm">Gerencie suas Séries, Módulos e ordene suas Aulas para entrega aos alunos.</p>
                </div>
                <Link
                    href="/studio/cursos/novo"
                    className="flex items-center gap-2 bg-primary hover:bg-primary-hover text-white px-5 py-2.5 rounded font-mono text-sm uppercase tracking-wider font-bold transition-all"
                >
                    <Plus size={18} /> Novo Curso
                </Link>
            </div>

            {/* Filters */}
            <div className="bg-[#0a0a0a] border border-[#1a1a1a] p-4 rounded flex flex-col sm:flex-row gap-4 mb-8">
                <div className="flex-1 relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-[#555]" size={18} />
                    <input
                        type="text"
                        value={search}
                        onChange={e => setSearch(e.target.value)}
                        placeholder="Buscar curso por título..."
                        className="w-full bg-[#111] border border-[#222] rounded py-2 pl-10 pr-4 text-white text-sm focus:outline-none focus:border-primary/50 transition-colors"
                    />
                </div>
                <select
                    value={statusFilter}
                    onChange={e => setStatusFilter(e.target.value)}
                    className="bg-[#111] border border-[#222] rounded py-2 px-4 text-[#888] text-sm focus:outline-none cursor-pointer hover:border-[#333]"
                >
                    <option value="all">Todos os Status</option>
                    <option value="published">Publicados</option>
                    <option value="draft">Rascunhos</option>
                </select>
            </div>

            {loading && (
                <div className="flex items-center justify-center py-20 text-[#555]">
                    <Loader2 size={24} className="animate-spin mr-3" /> Carregando cursos...
                </div>
            )}

            {!loading && filtered.length === 0 && (
                <div className="text-center py-20 border border-dashed border-[#222] rounded">
                    <Video size={40} className="mx-auto text-[#333] mb-4" />
                    <p className="text-[#555] text-sm mb-4">
                        {courses.length === 0 ? 'Você ainda não criou nenhum curso.' : 'Nenhum curso com esse filtro.'}
                    </p>
                    {courses.length === 0 && (
                        <Link href="/studio/cursos/novo" className="text-primary hover:text-white text-sm font-medium transition-colors">
                            + Criar meu primeiro curso
                        </Link>
                    )}
                </div>
            )}

            {!loading && filtered.length > 0 && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filtered.map(course => (
                        <CourseCard
                            key={course.id}
                            course={course}
                            onDelete={() => handleDelete(course.id, course.title)}
                            onTogglePublish={() => handleTogglePublish(course)}
                            onEdit={() => router.push(`/studio/cursos/${course.id}`)}
                        />
                    ))}
                </div>
            )}
        </div>
    );
}

function CourseCard({ course, onDelete, onTogglePublish, onEdit }: {
    course: Course;
    onDelete: () => void;
    onTogglePublish: () => void;
    onEdit: () => void;
}) {
    return (
        <div className="bg-[#0a0a0a] border border-[#1a1a1a] hover:border-[#333] transition-colors rounded-sm overflow-hidden group flex flex-col">
            <div className="h-40 relative bg-[#111] border-b border-[#1a1a1a] overflow-hidden">
                {course.thumbnail_url ? (
                    <img src={course.thumbnail_url} alt={course.title} className="absolute inset-0 w-full h-full object-cover opacity-40 group-hover:scale-105 transition-transform duration-700" />
                ) : (
                    <div className="absolute inset-0 opacity-20 group-hover:scale-105 transition-transform duration-700" style={{ background: 'linear-gradient(135deg, #6324b2, #7000F0)' }}></div>
                )}
                <div className="absolute top-3 left-3">
                    <span className={`text-[10px] font-mono uppercase tracking-widest px-2 py-0.5 rounded border ${course.is_published ? 'bg-primary/20 text-primary border-primary/30' : 'bg-[#1a1a1a] text-[#888] border-[#333]'}`}>
                        {course.is_published ? 'Publicado' : 'Rascunho'}
                    </span>
                </div>
            </div>

            <div className="p-5 flex-1 flex flex-col justify-between">
                <div>
                    <h3 className="font-heading font-bold text-white text-lg uppercase tracking-wide leading-tight mb-3">{course.title}</h3>
                    <div className="flex items-center gap-4 text-xs font-sans text-[#666] mb-1">
                        <span className="flex items-center gap-1.5"><Video size={14} /> {course.module_count} Módulos</span>
                        <span className="flex items-center gap-1.5"><PlayCircle size={14} className="text-[#444]" /> {course.lesson_count} Aulas</span>
                    </div>
                    <p className="text-xs font-mono text-[#555] mt-1">
                        R$ {Number(course.price).toFixed(2).replace('.', ',')} · {course.pricing_type === 'subscription' ? 'Assinatura' : 'Avulso'}
                    </p>
                </div>

                <div className="pt-4 border-t border-[#1a1a1a] flex justify-between items-center mt-4">
                    <div className="flex gap-3">
                        <button onClick={onEdit} className="text-xs font-mono text-[#888] hover:text-white uppercase tracking-widest flex items-center gap-1 transition-colors">
                            <Edit2 size={12} /> Editar
                        </button>
                        <button onClick={onTogglePublish} className="text-xs font-mono text-[#888] hover:text-secondary uppercase tracking-widest flex items-center gap-1 transition-colors">
                            {course.is_published ? <EyeOff size={12} /> : <Eye size={12} />}
                            {course.is_published ? 'Ocultar' : 'Publicar'}
                        </button>
                    </div>
                    <button onClick={onDelete} className="text-xs font-mono text-accent/50 hover:text-accent uppercase tracking-widest flex items-center gap-1 transition-colors">
                        <Trash2 size={12} /> Excluir
                    </button>
                </div>
            </div>
        </div>
    );
}

import { createServerClient } from '@supabase/ssr';
import { cookies } from 'next/headers';
import { Users, PlayCircle, TrendingUp, DollarSign } from 'lucide-react';

async function getStudioStats() {
    const cookieStore = await cookies();
    const supabase = createServerClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
        { cookies: { getAll: () => cookieStore.getAll() } }
    );

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return null;

    const { data: tenant } = await supabase.from('tenants').select('id').eq('owner_id', user.id).single();
    if (!tenant) return { students: 0, lessonsWatched: 0, publishedCourses: 0, revenue: 0, recentCourses: [], recentEnrollments: [] };

    const { data: courses } = await supabase
        .from('courses')
        .select('id, title, is_published, created_at')
        .eq('tenant_id', tenant.id)
        .order('created_at', { ascending: false });

    const courseIds = (courses || []).map(c => c.id);

    if (courseIds.length === 0) {
        return { students: 0, lessonsWatched: 0, publishedCourses: 0, revenue: 0, recentCourses: [], recentEnrollments: [] };
    }

    const [
        { count: students },
        { count: publishedCourses },
        { data: txData },
        { data: recentEnrollments },
    ] = await Promise.all([
        supabase.from('enrollments').select('id', { count: 'exact', head: true }).in('course_id', courseIds).eq('status', 'active'),
        supabase.from('courses').select('id', { count: 'exact', head: true }).eq('tenant_id', tenant.id).eq('is_published', true),
        supabase.from('transactions').select('amount').in('course_id', courseIds).eq('status', 'confirmed'),
        supabase.from('enrollments')
            .select('created_at, users:user_id(full_name), courses:course_id(title)')
            .in('course_id', courseIds)
            .order('created_at', { ascending: false })
            .limit(3),
    ]);

    const revenue = (txData || []).reduce((sum: number, t: any) => sum + Number(t.amount), 0);

    return {
        students: students || 0,
        publishedCourses: publishedCourses || 0,
        revenue,
        recentCourses: (courses || []).slice(0, 3),
        recentEnrollments: recentEnrollments || [],
    };
}

export default async function StudioDashboardPage() {
    const stats = await getStudioStats();
    const fmt = (v: number) => `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

    return (
        <div className="max-w-6xl mx-auto pb-10">
            <div className="mb-10">
                <h1 className="text-3xl font-heading font-bold text-white uppercase tracking-tight mb-2">Visão Geral</h1>
                <p className="text-[#888] font-sans text-sm">Acompanhe as métricas de retenção e faturamento da sua escola.</p>
            </div>

            {!stats ? (
                <div className="text-center py-20 text-[#555]">Carregando...</div>
            ) : (
                <>
                    {/* KPIs */}
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-10">
                        <MetricCard title="Alunos Ativos" value={String(stats.students)} icon={<Users />} />
                        <MetricCard title="Cursos Publicados" value={String(stats.publishedCourses)} icon={<PlayCircle />} />
                        <MetricCard title="Receita Confirmada" value={fmt(stats.revenue)} icon={<DollarSign />} isMoney />
                        <MetricCard title="Crescimento" value={stats.students > 0 ? '+' + stats.students : '0'} icon={<TrendingUp />} />
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                        {/* Cursos */}
                        <div className="lg:col-span-2 bg-[#0a0a0a] border border-[#1a1a1a] rounded-sm p-6">
                            <div className="flex justify-between items-center mb-6">
                                <h2 className="font-heading font-bold uppercase text-white tracking-wide">Seus Cursos</h2>
                                <a href="/studio/cursos" className="text-xs text-primary font-mono hover:text-white transition-colors">VER TODOS</a>
                            </div>

                            {stats.recentCourses.length === 0 ? (
                                <div className="text-center py-8 text-[#555] text-sm">
                                    <p>Nenhum curso criado ainda.</p>
                                    <a href="/studio/cursos/novo" className="text-primary hover:text-white text-xs mt-2 inline-block">+ Criar meu primeiro curso</a>
                                </div>
                            ) : (
                                <div className="flex flex-col gap-4">
                                    {stats.recentCourses.map((c: any) => (
                                        <a
                                            key={c.id}
                                            href={`/studio/cursos/${c.id}`}
                                            className="flex items-center gap-4 p-3 hover:bg-[#111] border border-transparent hover:border-[#222] transition-colors rounded"
                                        >
                                            <div className="w-16 h-10 bg-[#1a1a1a] rounded flex items-center justify-center shrink-0">
                                                <PlayCircle size={14} className="text-[#444]" />
                                            </div>
                                            <div className="flex-1">
                                                <h4 className="text-sm font-bold text-white">{c.title}</h4>
                                                <p className="text-xs text-[#666]">
                                                    {new Date(c.created_at).toLocaleDateString('pt-BR')}
                                                </p>
                                            </div>
                                            <div className="text-right">
                                                <span className={`text-[10px] font-mono uppercase px-2 py-0.5 rounded border ${
                                                    c.is_published
                                                        ? 'text-green-400 border-green-400/30 bg-green-400/10'
                                                        : 'text-[#666] border-[#333] bg-[#111]'
                                                }`}>
                                                    {c.is_published ? 'Publicado' : 'Rascunho'}
                                                </span>
                                            </div>
                                        </a>
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* Matrículas recentes */}
                        <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded-sm p-6">
                            <h2 className="font-heading font-bold uppercase text-white tracking-wide mb-6">Matrículas Recentes</h2>

                            {stats.recentEnrollments.length === 0 ? (
                                <div className="text-center py-8 text-[#555] text-sm">Nenhuma matrícula ainda.</div>
                            ) : (
                                <div className="flex flex-col gap-5 relative before:absolute before:left-1.5 before:top-2 before:bottom-2 before:w-[1px] before:bg-[#222]">
                                    {stats.recentEnrollments.map((e: any, i: number) => (
                                        <div key={i} className="pl-6 relative">
                                            <div className="absolute left-0 top-1 w-3 h-3 rounded-full border-[3px] border-[#0a0a0a] bg-primary/60" />
                                            <p className="text-sm text-[#ddd] mb-1 leading-snug">
                                                {e.users?.full_name || 'Aluno'} matriculou em <strong>{e.courses?.title || 'curso'}</strong>
                                            </p>
                                            <span className="text-xs text-[#555] font-mono">
                                                {new Date(e.created_at).toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' })}
                                            </span>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

function MetricCard({ title, value, icon, isMoney = false }: { title: string; value: string; icon: React.ReactNode; isMoney?: boolean }) {
    return (
        <div className="bg-[#0a0a0a] border border-[#1a1a1a] p-5 rounded-sm flex flex-col relative overflow-hidden group">
            <div className="text-[#888] mb-4 relative z-10 w-8 h-8 flex items-center justify-center bg-[#111] rounded border border-[#222]">
                {icon}
            </div>
            <div className="relative z-10">
                <p className="text-xs font-sans text-[#666] mb-1">{title}</p>
                <h3 className="text-2xl font-display font-medium text-white">{value}</h3>
            </div>
        </div>
    );
}

'use client';

import { UploadCloud, CheckCircle2, Film, Info, AlertTriangle, Loader2, Plus } from 'lucide-react';
import { useState, useEffect, useRef } from 'react';
import * as tus from 'tus-js-client';

interface Course { id: string; title: string; }
type UploadStatus = 'idle' | 'uploading' | 'processing' | 'success' | 'error' | 'paused';
export default function StudioUploadPage() {
    const [courses, setCourses] = useState<Course[]>([]);
    const [loadingCourses, setLoadingCourses] = useState(true);
    const [courseId, setCourseId] = useState('');
    const [moduleName, setModuleName] = useState('');
    const [lessonTitle, setLessonTitle] = useState('');
    const [dragActive, setDragActive] = useState(false);
    const [uploadStatus, setUploadStatus] = useState<UploadStatus | 'paused'>('idle');
    const [progress, setProgress] = useState(0);
    const [createdLessonId, setCreatedLessonId] = useState('');
    const uploadRef = useRef<tus.Upload | null>(null);

    useEffect(() => {
        fetch('/api/studio/courses')
            .then(r => r.json())
            .then(data => { setCourses(data.courses || []); setLoadingCourses(false); })
            .catch(() => setLoadingCourses(false));
    }, []);

    const isConfigured = !!(courseId && moduleName.trim() && lessonTitle.trim());

    const handleDrag = (e: React.DragEvent) => {
        e.preventDefault(); e.stopPropagation();
        if (e.type === 'dragenter' || e.type === 'dragover') setDragActive(true);
        else if (e.type === 'dragleave') setDragActive(false);
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault(); e.stopPropagation();
        setDragActive(false);
        if (!isConfigured) { alert('Preencha curso, módulo e título antes de enviar.'); return; }
        if (e.dataTransfer.files?.[0]) startUpload(e.dataTransfer.files[0]);
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        e.preventDefault();
        if (!isConfigured) { alert('Preencha curso, módulo e título antes de enviar.'); return; }
        if (e.target.files?.[0]) startUpload(e.target.files[0]);
    };

    const startUpload = async (file: File) => {
        try {
            setUploadStatus('uploading');
            setProgress(0);
            setCreatedLessonId('');

            // 1. Autoriza upload + cria video no Bunny
            const authRes = await fetch('/api/bunny/create', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ title: lessonTitle }),
            });
            const authData = await authRes.json();
            if (!authRes.ok) throw new Error(authData.error || 'Falha na autorização Bunny');
            const { videoId, libraryId, signature, expirationTime } = authData;

            // 2. Cria a aula no banco com video_id já vinculado
            const lessonRes = await fetch('/api/studio/lessons', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    course_id: courseId,
                    module_name: moduleName.trim(),
                    title: lessonTitle.trim(),
                    video_id: videoId,
                }),
            });
            const lessonData = await lessonRes.json();
            if (!lessonRes.ok) throw new Error(lessonData.error || 'Erro ao criar aula no banco');
            setCreatedLessonId(lessonData.lesson.id);

            // 3. TUS upload direto para o Bunny CDN (Pausável/Permitir Resume)
            const upload = new tus.Upload(file, {
                endpoint: 'https://video.bunnycdn.com/tusupload',
                retryDelays: [0, 3000, 5000, 10000, 20000],
                // @ts-ignore
                resume: true, // Auto save to localStorage
                removeFingerprintOnSuccess: true, // Cleanup localStorage on finish
                headers: {
                    AuthorizationSignature: signature,
                    AuthorizationExpire: String(expirationTime),
                    VideoId: videoId,
                    LibraryId: String(libraryId),
                },
                metadata: { filetype: file.type, title: lessonTitle },
                onError(error) { console.error('TUS falhou:', error); setUploadStatus('error'); },
                onProgress(bytesUploaded, bytesTotal) {
                    setProgress(Math.round((bytesUploaded / bytesTotal) * 100));
                },
                onSuccess() {
                    setUploadStatus('processing');
                    setTimeout(() => setUploadStatus('success'), 5000);
                },
            });

            uploadRef.current = upload;

            // Verifica se há envios parciais para retomar imediatamente
            upload.findPreviousUploads().then(function (previousUploads) {
                if (previousUploads.length) {
                    upload.resumeFromPreviousUpload(previousUploads[0]);
                }
                upload.start();
            });

        } catch (e: any) {
            console.error(e);
            setUploadStatus('error');
            alert(e.message);
        }
    };

    const handlePause = (e: React.MouseEvent) => {
        e.preventDefault();
        if (uploadRef.current && uploadStatus === 'uploading') {
            uploadRef.current.abort();
            setUploadStatus('paused');
        }
    };

    const handleResume = (e: React.MouseEvent) => {
        e.preventDefault();
        if (uploadRef.current && uploadStatus === 'paused') {
            uploadRef.current.start();
            setUploadStatus('uploading');
        }
    };

    const handleReset = () => {
        if (uploadRef.current && (uploadStatus === 'uploading' || uploadStatus === 'paused')) {
            uploadRef.current.abort();
        }
        uploadRef.current = null;
        setUploadStatus('idle'); setProgress(0);
        setLessonTitle(''); setModuleName(''); setCreatedLessonId('');
    };

    const uploaderBorderClass = dragActive && isConfigured
        ? 'border-primary bg-primary/5 scale-[1.01]'
        : !isConfigured
            ? 'border-[#1a1a1a] opacity-50 cursor-not-allowed'
            : 'border-[#333] hover:border-[#555] cursor-pointer';

    return (
        <div className="max-w-4xl mx-auto pb-20">
            <h1 className="text-3xl font-heading font-bold text-white uppercase tracking-tight mb-2">Central de Upload</h1>
            <p className="text-[#888] font-sans text-sm mb-8 border-b border-[#1a1a1a] pb-6">
                Envie vídeos MP4 direto da câmera. O Bunny.net converte para HLS e vincula automaticamente à aula no banco.
            </p>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                <div className="md:col-span-2 space-y-6">

                    {/* Step 1 */}
                    <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded-sm p-6 space-y-4">
                        <h2 className="text-white font-heading font-bold uppercase tracking-wide text-sm flex items-center gap-2">
                            <span className="w-5 h-5 rounded-full bg-primary text-white text-[10px] flex items-center justify-center font-bold">1</span>
                            Configure a Aula
                        </h2>

                        <div className="space-y-2">
                            <label className="text-xs font-mono uppercase tracking-widest text-[#888]">Curso *</label>
                            {loadingCourses ? (
                                <div className="flex items-center gap-2 text-[#555] text-sm py-3">
                                    <Loader2 size={14} className="animate-spin" /> Carregando cursos...
                                </div>
                            ) : courses.length === 0 ? (
                                <div className="text-[#555] text-sm py-2">
                                    Nenhum curso. <a href="/studio/cursos/novo" className="text-primary hover:text-white">Criar curso</a>
                                </div>
                            ) : (
                                <select
                                    value={courseId}
                                    onChange={e => setCourseId(e.target.value)}
                                    disabled={uploadStatus !== 'idle'}
                                    className="w-full bg-[#111] border border-[#222] focus:border-primary/50 rounded py-3 px-4 text-white text-sm outline-none cursor-pointer disabled:opacity-50"
                                >
                                    <option value="">Selecione um curso...</option>
                                    {courses.map(c => <option key={c.id} value={c.id}>{c.title}</option>)}
                                </select>
                            )}
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-xs font-mono uppercase tracking-widest text-[#888]">Módulo *</label>
                                <input
                                    type="text" value={moduleName}
                                    onChange={e => setModuleName(e.target.value)}
                                    disabled={uploadStatus !== 'idle'}
                                    placeholder="Ex: Módulo 1 — Fundamentos"
                                    className="w-full bg-[#111] border border-[#222] focus:border-primary/50 rounded py-3 px-4 text-white text-sm outline-none transition-colors disabled:opacity-50"
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-mono uppercase tracking-widest text-[#888]">Título da Aula *</label>
                                <input
                                    type="text" value={lessonTitle}
                                    onChange={e => setLessonTitle(e.target.value)}
                                    disabled={uploadStatus !== 'idle'}
                                    placeholder="Ex: Dissociação de Ombros"
                                    className="w-full bg-[#111] border border-[#222] focus:border-primary/50 rounded py-3 px-4 text-white text-sm outline-none transition-colors disabled:opacity-50"
                                />
                            </div>
                        </div>
                        {!isConfigured && uploadStatus === 'idle' && (
                            <p className="text-[10px] text-[#555] font-mono">Preencha todos os campos para habilitar o upload.</p>
                        )}
                    </div>

                    {/* Step 2 */}
                    <div>
                        <h2 className="text-white font-heading font-bold uppercase tracking-wide text-sm flex items-center gap-2 mb-3">
                            <span className="w-5 h-5 rounded-full bg-primary text-white text-[10px] flex items-center justify-center font-bold">2</span>
                            Enviar Vídeo
                        </h2>

                        <form
                            onDragEnter={handleDrag} onDragLeave={handleDrag}
                            onDragOver={handleDrag} onDrop={handleDrop}
                            className={`border-2 border-dashed rounded-sm flex flex-col items-center justify-center p-12 transition-all duration-300 relative overflow-hidden bg-[#0A0A0A] ${uploaderBorderClass} ${uploadStatus !== 'idle' ? 'pointer-events-none' : ''}`}
                        >
                            <input
                                type="file" accept="video/mp4,video/quicktime"
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer disabled:cursor-not-allowed"
                                onChange={handleChange}
                                disabled={uploadStatus !== 'idle' || !isConfigured}
                            />

                            {uploadStatus === 'idle' && (
                                <>
                                    <div className="w-16 h-16 rounded-full bg-[#111] border border-[#222] flex items-center justify-center mb-6">
                                        <UploadCloud size={32} className={isConfigured ? 'text-[#666]' : 'text-[#333]'} />
                                    </div>
                                    <h3 className="font-heading font-bold text-lg text-white uppercase mb-2">
                                        {isConfigured ? 'Arraste o Vídeo Aqui' : 'Configure a aula acima'}
                                    </h3>
                                    <p className="text-sm font-sans text-[#666] text-center max-w-sm">MP4 ou MOV até 2.5GB. Suporte a Resumable Upload (Pode Pausar).</p>
                                    {isConfigured && (
                                        <button type="button" className="mt-8 px-6 py-2 bg-[#1a1a1a] hover:bg-[#222] text-white font-mono text-xs uppercase tracking-widest border border-[#333] rounded">
                                            Procurar Arquivo
                                        </button>
                                    )}
                                </>
                            )}

                            {(uploadStatus === 'uploading' || uploadStatus === 'paused') && (
                                <div className="w-full text-center z-10">
                                    <div className="flex items-center justify-between mb-2 text-xs font-mono uppercase tracking-widest text-[#888]">
                                        <span>{uploadStatus === 'paused' ? 'Pausado' : 'Enviando para Bunny CDN...'}</span>
                                        <span className="text-white">{progress}%</span>
                                    </div>
                                    <div className="w-full h-2 bg-[#111] rounded overflow-hidden border border-[#222]">
                                        <div className={`h-full transition-all duration-300 ${uploadStatus === 'paused' ? 'bg-[#555]' : 'bg-primary'}`} style={{ width: `${progress}%` }} />
                                    </div>

                                    <div className="flex items-center justify-center gap-4 mt-6">
                                        {uploadStatus === 'uploading' ? (
                                            <button onClick={handlePause} className="px-6 py-2 bg-[#1a1a1a] hover:bg-[#222] text-white font-mono text-xs uppercase tracking-widest border border-[#333] rounded transition-colors">
                                                Pausar Upload
                                            </button>
                                        ) : (
                                            <button onClick={handleResume} className="px-6 py-2 bg-primary/20 hover:bg-primary/30 text-primary font-mono text-xs uppercase tracking-widest border border-primary/50 rounded shadow-[0_0_15px_rgba(99,36,178,0.2)] transition-all">
                                                Retomar Upload
                                            </button>
                                        )}
                                        <button onClick={handleReset} className="px-6 py-2 text-red-400/70 hover:text-red-400 font-mono text-xs uppercase tracking-widest transition-colors">
                                            Cancelar
                                        </button>
                                    </div>
                                    <p className="text-[#555] text-[10px] font-mono mt-4">Pode fechar a aba se a energia cair. Retomaremos automaticamente.</p>
                                </div>
                            )}

                            {uploadStatus === 'processing' && (
                                <div className="w-full text-center z-10 flex flex-col items-center gap-4">
                                    <div className="w-12 h-12 rounded-full border-t-2 border-r-2 border-primary animate-spin" />
                                    <div>
                                        <p className="font-heading font-bold text-white uppercase">Convertendo HLS na Nuvem...</p>
                                        <p className="text-xs text-[#888] font-mono mt-1">Fragmentando para anti-pirataria. Aguarde...</p>
                                    </div>
                                </div>
                            )}

                            {uploadStatus === 'success' && (
                                <div className="w-full text-center z-10 flex flex-col items-center gap-4">
                                    <div className="w-16 h-16 rounded-full bg-green-500/20 border border-green-500/50 flex items-center justify-center">
                                        <CheckCircle2 size={32} className="text-green-500" />
                                    </div>
                                    <div>
                                        <p className="font-heading font-bold text-green-500 uppercase text-xl">Upload Concluído!</p>
                                        <p className="text-xs text-[#888] font-mono mt-1">Aula criada e vídeo vinculado com sucesso.</p>
                                        {createdLessonId && (
                                            <p className="text-[10px] text-[#555] font-mono mt-1">lesson_id: {createdLessonId.slice(0, 20)}...</p>
                                        )}
                                    </div>
                                    <button onClick={handleReset} className="mt-2 px-6 py-2 bg-[#1a1a1a] hover:bg-[#222] text-white font-mono text-xs uppercase tracking-widest border border-[#333] rounded">
                                        Subir Novo Vídeo
                                    </button>
                                </div>
                            )}

                            {uploadStatus === 'error' && (
                                <div className="w-full text-center z-10 flex flex-col items-center gap-4">
                                    <AlertTriangle size={40} className="text-red-400" />
                                    <p className="font-heading font-bold text-red-400 uppercase">Falha no Upload</p>
                                    <button onClick={handleReset} className="px-6 py-2 bg-[#1a1a1a] hover:bg-[#222] text-white font-mono text-xs uppercase tracking-widest border border-[#333] rounded">
                                        Tentar Novamente
                                    </button>
                                </div>
                            )}
                        </form>
                    </div>
                </div>

                <div className="md:col-span-1 flex flex-col gap-6">
                    <div className="bg-[#111] border border-primary/20 rounded p-5 relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-3 opacity-20"><Film size={40} className="text-primary" /></div>
                        <h4 className="font-heading font-bold text-white uppercase mb-3 flex items-center gap-2 relative z-10">
                            <Info size={16} className="text-primary" /> Como funciona
                        </h4>
                        <p className="text-xs font-sans text-[#aaa] leading-relaxed relative z-10">
                            O vídeo vai direto para o Bunny Stream (HLS criptografado). O <strong className="text-white">video_id é gravado na aula automaticamente</strong> — sem etapa manual.
                        </p>
                    </div>

                    <div className="bg-accent/5 border border-accent/20 rounded p-5">
                        <h4 className="font-heading font-bold text-accent uppercase mb-3 flex items-center gap-2">
                            <AlertTriangle size={16} /> Qualidade
                        </h4>
                        <ul className="text-xs font-sans text-[#888] space-y-2 list-disc pl-4">
                            <li>Máximo: <strong className="text-white">2.5 GB / Aula</strong></li>
                            <li>Formatos: <strong className="text-white">.MP4 ou .MOV</strong></li>
                            <li>FPS: <strong className="text-white">60fps</strong> p/ dança</li>
                            <li>Luz limpa para melhor imagem</li>
                        </ul>
                    </div>

                    <a href="/studio/cursos" className="flex items-center gap-2 text-[#888] hover:text-white text-sm font-mono transition-colors">
                        <Plus size={14} /> Gerenciar Cursos
                    </a>
                </div>
            </div>
        </div>
    );
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { MessageSquare, Send, Heart, CornerDownRight } from 'lucide-react'
import { createClient } from '@/utils/supabase/client'

interface CommunityBoardProps {
    lessonId: string
}

interface CommentUser {
    id: string
    full_name: string | null
    avatar_url: string | null
}

interface Comment {
    id: string
    content: string
    likes: number
    created_at: string
    parent_id: string | null
    users: CommentUser | null
}

export function CommunityBoard({ lessonId }: CommunityBoardProps) {
    const supabase = createClient()
    const [newComment, setNewComment] = useState('')
    const [replyTo, setReplyTo] = useState<{ id: string; name: string } | null>(null)
    const [comments, setComments] = useState<Comment[]>([])
    const [currentUserProfile, setCurrentUserProfile] = useState<{ id: string; full_name?: string; avatar_url?: string } | null>(null)
    const [loading, setLoading] = useState(true)
    const [likingIds, setLikingIds] = useState<Set<string>>(new Set())

    const timeAgo = (dateStr: string) => {
        const diff = Math.floor((new Date().getTime() - new Date(dateStr).getTime()) / 1000);
        if (diff < 60) return `Agora mesmo`;
        if (diff < 3600) return `${Math.floor(diff / 60)}m atrás`;
        if (diff < 86400) return `${Math.floor(diff / 3600)}h atrás`;
        return `${Math.floor(diff / 86400)}d atrás`;
    }

    const fetchComments = useCallback(async () => {
        const { data, error } = await supabase
            .from('comments')
            .select(`
                id,
                content,
                likes,
                created_at,
                parent_id,
                users (
                    id,
                    full_name,
                    avatar_url
                )
            `)
            .eq('lesson_id', lessonId)
            .order('created_at', { ascending: false })

        if (data) {
            const normalized: Comment[] = data.map((row: any) => ({
                ...row,
                users: Array.isArray(row.users) ? row.users[0] ?? null : row.users,
            }))
            setComments(normalized)
        }
        if (error) console.error("Erro ao buscar mural:", error)
        setLoading(false)
    }, [lessonId, supabase])

    useEffect(() => {
        const fetchUser = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            if (user) {
                const { data: profile } = await supabase.from('users').select('id, full_name, avatar_url').eq('id', user.id).single()
                setCurrentUserProfile(profile || { id: user.id })
            }
        }
        fetchUser()
        fetchComments()

        // Realtime: on INSERT, fetch only the new comment (not all) and prepend
        const channel = supabase.channel(`public:comments:lesson_${lessonId}`)
            .on(
                'postgres_changes',
                { event: 'INSERT', schema: 'public', table: 'comments', filter: `lesson_id=eq.${lessonId}` },
                async (payload) => {
                    const { data: newItem } = await supabase
                        .from('comments')
                        .select(`id, content, likes, created_at, parent_id, users(id, full_name, avatar_url)`)
                        .eq('id', payload.new.id)
                        .single()

                    if (newItem) {
                        const normalized: Comment = {
                            ...(newItem as any),
                            users: Array.isArray((newItem as any).users) ? (newItem as any).users[0] ?? null : (newItem as any).users,
                        }
                        setComments(prev => [normalized, ...prev])
                    }
                }
            )
            .on(
                'postgres_changes',
                { event: 'UPDATE', schema: 'public', table: 'comments', filter: `lesson_id=eq.${lessonId}` },
                (payload) => {
                    // Update only the changed comment's likes in local state
                    setComments(prev => prev.map(c =>
                        c.id === payload.new.id ? { ...c, likes: payload.new.likes } : c
                    ))
                }
            )
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [lessonId, supabase, fetchComments])

    const handleSend = async () => {
        if (!newComment.trim() || !currentUserProfile?.id) return

        const contentToSend = newComment
        const parentId = replyTo?.id || null
        setNewComment('')
        setReplyTo(null)

        const { error } = await supabase.from('comments').insert({
            lesson_id: lessonId,
            user_id: currentUserProfile.id,
            content: contentToSend,
            parent_id: parentId,
        })

        if (error) {
            console.error("Erro ao postar comentário:", error)
            setNewComment(contentToSend)
        }
    }

    const handleLike = async (commentId: string, currentLikes: number) => {
        if (likingIds.has(commentId)) return
        setLikingIds(prev => new Set(prev).add(commentId))

        // Optimistic update
        setComments(prev => prev.map(c => c.id === commentId ? { ...c, likes: currentLikes + 1 } : c))

        const { error } = await supabase
            .from('comments')
            .update({ likes: currentLikes + 1 })
            .eq('id', commentId)

        if (error) {
            // Revert on error
            setComments(prev => prev.map(c => c.id === commentId ? { ...c, likes: currentLikes } : c))
        }

        setLikingIds(prev => { const s = new Set(prev); s.delete(commentId); return s; })
    }

    const parentComments = comments.filter(c => !c.parent_id)
    const getReplies = (parentId: string) => comments.filter(c => c.parent_id === parentId).reverse()

    return (
        <div className="w-full mt-8">
            <div className="flex items-center gap-3 mb-6">
                <div className="w-10 h-10 rounded-sm bg-secondary/10 border border-secondary/30 flex items-center justify-center">
                    <MessageSquare size={20} className="text-secondary" />
                </div>
                <div>
                    <h2 className="font-heading text-xl uppercase tracking-widest text-white">Mural da Aula</h2>
                    <p className="text-[10px] font-sans text-[#666]">Discuta técnicas e tire dúvidas ao vivo</p>
                </div>
            </div>

            {/* Input Form */}
            <div className="bg-[#0A0A0A] border border-[#222] rounded-sm p-4 mb-8 flex gap-4 items-start">
                <div className="w-10 h-10 rounded-full bg-[#1A1A1A] flex items-center justify-center font-heading text-primary border border-primary/30 shrink-0 overflow-hidden">
                    {currentUserProfile?.avatar_url ? (
                        <img src={currentUserProfile.avatar_url} alt="Profile" className="w-full h-full object-cover grayscale" />
                    ) : (
                        currentUserProfile?.full_name?.substring(0, 2).toUpperCase() || "YOU"
                    )}
                </div>
                <div className="flex-1 relative">
                    {replyTo && (
                        <div className="flex items-center gap-2 mb-2 text-xs text-[#888] font-sans">
                            <CornerDownRight size={12} className="text-secondary" />
                            <span>Respondendo <span className="text-white">{replyTo.name}</span></span>
                            <button onClick={() => setReplyTo(null)} className="ml-auto text-[#555] hover:text-white">✕</button>
                        </div>
                    )}
                    <textarea
                        value={newComment}
                        onChange={e => setNewComment(e.target.value)}
                        onKeyDown={e => { if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) handleSend() }}
                        placeholder={replyTo ? `Responda ${replyTo.name}...` : "Compartilhe uma dúvida ou insight..."}
                        className="w-full bg-[#111] border border-[#222] focus:border-secondary/50 rounded-sm p-3 min-h-[80px] text-sm text-white font-sans outline-none transition-colors resize-none placeholder:text-[#555]"
                    />
                    <div className="absolute right-2 bottom-2">
                        <button
                            onClick={handleSend}
                            disabled={!newComment.trim()}
                            className="bg-secondary text-black p-2 rounded-sm hover:bg-white transition-colors disabled:opacity-50 disabled:hover:bg-secondary"
                        >
                            <Send size={16} />
                        </button>
                    </div>
                </div>
            </div>

            {/* Comments List */}
            {loading ? (
                <div className="animate-pulse flex flex-col gap-4">
                    <div className="h-16 bg-[#111] rounded-sm w-full"></div>
                    <div className="h-16 bg-[#111] rounded-sm w-full"></div>
                </div>
            ) : parentComments.length === 0 ? (
                <p className="text-[#555] text-sm italic py-4">Nenhum comentário ainda. Seja o primeiro a puxar o assunto!</p>
            ) : (
                <div className="space-y-6">
                    {parentComments.map(comment => {
                        const replies = getReplies(comment.id)

                        return (
                            <div key={comment.id} className="flex gap-4">
                                <div className="w-10 h-10 rounded-full bg-[#222] flex items-center justify-center font-heading text-[#888] border border-[#333] shrink-0 overflow-hidden">
                                    {comment.users?.avatar_url ? (
                                        <img src={comment.users.avatar_url} alt="User" className="w-full h-full object-cover grayscale" />
                                    ) : (
                                        comment.users?.full_name?.substring(0, 2).toUpperCase() || "?"
                                    )}
                                </div>
                                <div className="flex-1">
                                    <div className="flex items-baseline gap-2 mb-1">
                                        <span className="font-heading text-sm uppercase text-white hover:text-primary transition-colors cursor-pointer">
                                            {comment.users?.full_name || 'DANCER ANÔNIMO'}
                                        </span>
                                        <span className="text-[10px] text-[#555] font-sans ml-auto">{timeAgo(comment.created_at)}</span>
                                    </div>

                                    <p className="text-sm font-sans text-[#ccc] leading-relaxed mb-2">
                                        {comment.content}
                                    </p>

                                    <div className="flex items-center gap-4 mb-4">
                                        <button
                                            onClick={() => handleLike(comment.id, comment.likes)}
                                            disabled={likingIds.has(comment.id)}
                                            className="flex items-center gap-1.5 text-xs text-[#666] hover:text-secondary transition-colors group disabled:opacity-50"
                                        >
                                            <Heart size={14} className="group-hover:fill-secondary/20" /> {comment.likes}
                                        </button>
                                        <button
                                            onClick={() => setReplyTo({ id: comment.id, name: comment.users?.full_name || 'Dancer' })}
                                            className="text-xs text-[#666] hover:text-white transition-colors font-sans uppercase tracking-widest text-[10px]"
                                        >
                                            Responder
                                        </button>
                                    </div>

                                    {/* Replies */}
                                    {replies.length > 0 && (
                                        <div className="pl-4 border-l-2 border-[#222] space-y-4">
                                            {replies.map(reply => (
                                                <div key={reply.id} className="flex gap-3">
                                                    <div className="w-8 h-8 rounded-full bg-[#111] flex items-center justify-center font-heading text-white border border-[#333] shrink-0 overflow-hidden">
                                                        {reply.users?.avatar_url ? (
                                                            <img src={reply.users.avatar_url} alt="User" className="w-full h-full object-cover grayscale" />
                                                        ) : (
                                                            reply.users?.full_name?.substring(0, 2).toUpperCase() || "?"
                                                        )}
                                                    </div>
                                                    <div className="flex-1">
                                                        <div className="flex items-baseline gap-2 mb-0.5">
                                                            <span className="font-heading text-xs uppercase text-white cursor-pointer hover:text-primary transition-colors">
                                                                {reply.users?.full_name || 'DANCER ANÔNIMO'}
                                                            </span>
                                                            <span className="text-[10px] text-[#555] font-sans ml-auto">{timeAgo(reply.created_at)}</span>
                                                        </div>
                                                        <p className="text-xs font-sans text-[#aaa] leading-relaxed mb-1">
                                                            {reply.content}
                                                        </p>
                                                        <button
                                                            onClick={() => handleLike(reply.id, reply.likes)}
                                                            disabled={likingIds.has(reply.id)}
                                                            className="flex items-center gap-1.5 text-xs text-[#666] hover:text-secondary transition-colors group disabled:opacity-50"
                                                        >
                                                            <Heart size={12} className="group-hover:fill-secondary/20" /> {reply.likes}
                                                        </button>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                        )
                    })}
                </div>
            )}
        </div>
    )
}

import { createClient } from '@supabase/supabase-js';
import { createServerClient } from '@supabase/ssr';
import { cookies } from 'next/headers';
import { Trophy } from 'lucide-react';

interface LeaderboardRow {
    user_id: string;
    full_name: string | null;
    avatar_url: string | null;
    weekly_xp: number;
    rank: number;
}

async function getLeaderboard(): Promise<LeaderboardRow[]> {
    const supabase = createClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.SUPABASE_SERVICE_ROLE_KEY!
    );
    const { data } = await supabase
        .from('leaderboard_weekly')
        .select('user_id, full_name, avatar_url, weekly_xp')
        .order('weekly_xp', { ascending: false })
        .limit(10);

    return (data || []).map((row: any, i: number) => ({ ...row, rank: i + 1 }));
}

async function getCurrentUserId(): Promise<string | null> {
    const cookieStore = await cookies();
    const supabase = createServerClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
        { cookies: { getAll: () => cookieStore.getAll() } }
    );
    const { data: { user } } = await supabase.auth.getUser();
    return user?.id ?? null;
}

export async function LeaderboardWeekly() {
    const [leaderboard, currentUserId] = await Promise.all([getLeaderboard(), getCurrentUserId()]);

    if (leaderboard.length === 0) {
