                        <p className="text-[10px] font-sans text-[#666]">Ranking reinicia todo domingo meia-noite</p>
                    </div>
                </div>
                <p className="text-[#555] text-sm text-center py-8">Nenhum dado de XP ainda. Complete aulas para aparecer aqui!</p>
