'use client';

import { useState, useEffect } from 'react';
import Image from 'next/image';

export function PowerOnPreloader({ children }: { children: React.ReactNode }) {
    const [hasStarted, setHasStarted] = useState(false);
    const [isPoweringUp, setIsPoweringUp] = useState(false);

    useEffect(() => {
        // Pula a animação se for a mesma sessão pra não irritar quem dá refresh
        if (sessionStorage.getItem('xtage-powered')) {
            setHasStarted(true);
        }
    }, []);

    const handlePowerOn = () => {
        setIsPoweringUp(true);
        sessionStorage.setItem('xtage-powered', 'true');
        // Simula a inicialização brutalista que escala e esvanece (1.2s)
        setTimeout(() => {
            setHasStarted(true);
        }, 1200);
    };

    if (hasStarted) return <>{children}</>;

    return (
        <>
            <div className="fixed inset-0 z-[99999] bg-black flex flex-col items-center justify-center overflow-hidden">
                {/* Glow/Luz atrás do sticker */}
                <div className={`absolute w-64 h-64 bg-primary/30 rounded-full blur-[80px] transition-all duration-1000 ${isPoweringUp ? 'opacity-0 scale-150' : 'opacity-100 animate-pulse-slow'}`}></div>

                {/* Sticker Button / Simbolo de ON */}
                <button
                    onClick={handlePowerOn}
                    className={`relative z-10 w-48 h-48 sm:w-64 sm:h-64 rounded-full flex items-center justify-center transition-all duration-[1200ms] outline-none ${isPoweringUp ? 'scale-[4] opacity-0 blur-xl' : 'scale-100 cursor-pointer hover:scale-105 active:scale-95'}`}
                >
                    <Image
                        src="/images/xpace-on-sticker.png"
                        alt="Power On XPACE"
                        fill
                        className="object-contain"
                        priority
                    />
                </button>

                {/* Hint Fading */}
                <div className={`mt-16 text-center transition-opacity duration-300 ${isPoweringUp ? 'opacity-0' : 'opacity-100'}`}>
                    <p className="text-white font-bold tracking-[0.3em] uppercase text-xs opacity-60 animate-pulse">Tap to Power On</p>
                </div>
            </div>
            {/* Renderiza as children escondidas apenas por segurança do SEO e Hydration */}
            <div style={{ display: 'none' }}>{children}</div>
        </>
    );
}

import { createServerClient } from '@supabase/ssr'
import { NextResponse, type NextRequest } from 'next/server'

export async function updateSession(request: NextRequest) {
    let supabaseResponse = NextResponse.next({
        request,
    })

    const supabase = createServerClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
        {
            cookies: {
                getAll() {
                    return request.cookies.getAll()
                },
                setAll(cookiesToSet) {
                    cookiesToSet.forEach(({ name, value, options }) => request.cookies.set(name, value))
                    supabaseResponse = NextResponse.next({
                        request,
                    })
                    cookiesToSet.forEach(({ name, value, options }) =>
                        supabaseResponse.cookies.set(name, value, options)
                    )
                },
            },
        }
    )

    const {
        data: { user },
    } = await supabase.auth.getUser()

    // Rotas públicas que não precisam de sessão (Ignorar Arquivos Estáticos/API Interna já blindada pelo Next)
    const isPublicRoute =
        request.nextUrl.pathname.startsWith('/login') ||
        request.nextUrl.pathname.startsWith('/register') ||
        request.nextUrl.pathname.startsWith('/forgot-password') ||
        request.nextUrl.pathname.startsWith('/checkout') ||
        request.nextUrl.pathname.startsWith('/auth') || // <--- EXCEÇÃO PARA CALLBACK OAuth (Google/Apple)
        request.nextUrl.pathname.startsWith('/api') || // <--- EXCEÇÃO CRÍTICA PARA AS APIS (Checkout Asaas e Webhooks)
        request.nextUrl.pathname === '/' || // Home page
        // Regex simplificada para permitir acesso livre à página dinâmica de perfil "/slug" sem afetar "/dashboard/..."
        /^\/[a-zA-Z0-9_-]+$/.test(request.nextUrl.pathname) && !request.nextUrl.pathname.startsWith('/dashboard') && !request.nextUrl.pathname.startsWith('/api')

    if (!user && !isPublicRoute) {
        // Redireciona usuários não logados para a tela de login
        const url = request.nextUrl.clone()
        url.pathname = '/login'
        return NextResponse.redirect(url)
    }

    // --- FEATURE ANTI-PIRATARIA E FIREWALL (RBAC) ---
    if (user && !isPublicRoute) {

        const isMasterRoute = request.nextUrl.pathname.startsWith('/master')
        const isStudioRoute = request.nextUrl.pathname.startsWith('/studio')

        // Apenas rodar validação se for estritamente necessário (Rotas Premium)
        if (isMasterRoute || isStudioRoute) {

            // Otimização de Performance: Lemos a role direto do JWT em vez de bater no banco.
            const role = user?.app_metadata?.role || user?.user_metadata?.role || 'aluno'

            // Proteção Nível Supremo: Apenas o dono
            if (isMasterRoute && role !== 'admin') {
                if (process.env.NODE_ENV === 'development') console.log("RBAC BLOQUEADO: Tentou Master mas não é admin. Role Final:", role)
                const url = request.nextUrl.clone()
                url.pathname = '/dashboard'
                return NextResponse.redirect(url)
            }

            // Proteção Inquilinos: Apenas Escolas e Admin
            if (isStudioRoute && role !== 'escola' && role !== 'professor' && role !== 'admin') {
                if (process.env.NODE_ENV === 'development') console.log("RBAC BLOQUEADO: Tentou Studio mas não é criador/admin. Role Final:", role)
                const url = request.nextUrl.clone()
                url.pathname = '/dashboard'
                return NextResponse.redirect(url)
            }
        }

        // Single Session Lock (Anti-Pirataria)
        // Validates that the current JWT matches the most recent session in user_sessions.
        // If another device logged in, the older session is invalidated.
        // Controlled by env var to allow disabling during debugging.
        if (process.env.ENABLE_SESSION_LOCK !== 'false') {
            const { data: isValidSession } = await supabase.rpc('is_valid_session')
            if (isValidSession === false) {
                await supabase.auth.signOut()
                const url = request.nextUrl.clone()
                url.pathname = '/login'
                url.searchParams.set('reason', 'session_revoked')
                return NextResponse.redirect(url)
            }
        }
    }

    return supabaseResponse
}
